#include <bits/stdc++.h>
using namespace std;
int n,m,w[26],dp[2003][2003];
int main(){
	string s;
	cin>>n>>m>>s;
	for(int i=1;i<=n;i++){
		char a;int b,c;
		cin>>a>>b>>c;
		w[a-'a']=min(b,c);
	}
	for(int len=2;len<=m;len++){
		for(int l=1;l+len-1<=m;l++){
			int r=l+len-1;
			if(s[l-1]==s[r-1])dp[l][r]=dp[l+1][r-1];
			else dp[l][r]=min(dp[l+1][r]+w[s[l-1]-'a'],dp[l][r-1]+w[s[r-1]-'a']);
		}
	}
	cout<<dp[1][m];
	return 0;
}
